#include <bits/stdc++.h>
#include <boost/multiprecision/cpp_int.hpp>
using namespace std;
using boost::multiprecision::cpp_int;
struct DSU{vector<int> p;DSU(int n):p(n){iota(p.begin(),p.end(),0);}int find(int x){return p[x]==x?x:p[x]=find(p[x]);}bool unite(int a,int b){a=find(a);b=find(b);if(a==b) return false;p[b]=a;return true;}};
cpp_int determinantBareiss(vector<vector<cpp_int>> a){int n=a.size();if(n==0) return 1;for(int i=0;i<n-1;i++){
    for(int j=i+1;j<n;j++){
        for(int k=i+1;k<n;k++){
            a[j][k]=(a[j][k]*a[i][i]-a[j][i]*a[i][k]);
            if(i>0) a[j][k]/=a[i-1][i-1];
        }
    }
    for(int j=i+1;j<n;j++) a[j][i]=0;
}
return a[n-1][n-1];}
int main(){ios::sync_with_stdio(false);cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; while(T--){int n;cin>>n;vector<string> mat(n);for(int i=0;i<n;i++)cin>>mat[i];int p;cin>>p;DSU dsu(n);
        bool cycle=false;for(int i=0;i<p;i++){int u,v;cin>>u>>v;--u;--v; if(!dsu.unite(u,v)) cycle=true;}
        if(cycle){cout<<0<<"\n";continue;}
        unordered_map<int,int> compId;int id=0;vector<int> comp(n);
        for(int i=0;i<n;i++){int r=dsu.find(i);if(compId.find(r)==compId.end()) compId[r]=id++; comp[i]=compId[r];}
        int k=id; if(k==1){cout<<1<<"\n";continue;}
        vector<vector<cpp_int>> L(k, vector<cpp_int>(k,0));
        for(int i=0;i<n;i++){
            for(int j=i+1;j<n;j++) if(mat[i][j]=='1'){
                int a=comp[i], b=comp[j];
                if(a==b) continue;
                L[a][a]++; L[b][b]++; L[a][b]--; L[b][a]--; }
        }
        int m=k-1; vector<vector<cpp_int>> M(m, vector<cpp_int>(m));
        for(int i=0;i<m;i++) for(int j=0;j<m;j++) M[i][j]=L[i][j];
        cpp_int ans=determinantBareiss(M);
        cout<<ans<<"\n";
    }
    return 0; }
